using Ares.Common.Constants;
using Ares.Common.DTOs;
using Ares.Common.Models.Chat;
using Ares.Common.Models.Chat.Historic;
using Ares.Common.Models.Chat.Image;
using Ares.Common.Models.Chat.Price;
using Ares.Common.Models.Data;
using Ares.Common.Objects;
using Ares.Common.Util;
using Ares.Discord.Service.Neural;
using Ares.Discord.Services.Api;
using Ares.Discord.Util;
using Discord;
using Discord.Rest;
using Discord.WebSocket;
using System.Text.RegularExpressions;

namespace Ares.Discord.Listener.Chat;

public class ReceivedContentListener
{
    private readonly DiscordSocketClient _client;

    private static GuildService? _guildService { get; set; }
    private static UserService? _userService { get; set; }

    /// <summary>
    /// Constructor that initializes the Received Intent Listener with a Discord client.
    /// </summary>
    /// <param name="client">The Discord client</param>
    public ReceivedContentListener(DiscordSocketClient client)
    {
        _client = client ?? throw new ArgumentNullException(nameof(client));
        _client.MessageReceived += MessageReceivedHandler;

        _guildService = Program.GuildService;
        _userService = Program.UserService;

        if (_guildService == null || _userService == null)
        {
            AresLogger.Log(nameof(NeuralService), "Guild or User service is not initialized.", severity: Severity.Error);
            throw new InvalidOperationException("Guild or User service is not initialized.");
        }
    }

    /// <summary>
    /// Handler for incoming messages.
    /// </summary>
    private Task MessageReceivedHandler(SocketMessage args)
    {
        _ = Task.Run(async () =>
        {
            try
            {
                if (args is not SocketUserMessage message)
                    return;

                if (!(args.Channel is SocketTextChannel channel))
                    return;

                IUser iuser = args.Author;
                if (iuser.Id.Equals(_client.CurrentUser.Id))
                    return;

                SocketGuild socketGuild = channel.Guild;
                if (socketGuild == null)
                {
                    await channel.SendMessageAsync(AppConstants.UnableGetMember);
                    return;
                }

                ApiResult<Guild>? guildResult = await _guildService!.GetGuild(socketGuild.Id);
                if (guildResult == null || !guildResult.Success || guildResult.Data == null)
                    return;
                Guild guild = guildResult.Data;

                ApiResult<User>? userResult = await _userService!.GetUser(iuser.Id, useCache: true);
                if (userResult == null || !userResult.Success || userResult.Data == null)
                    return;
                User user = userResult.Data;

                ApiResult<bool>? hasActiveConversationResult = await _userService!.HasActiveConversation(user.Id, guild.Id, channelId: channel.Id);
                if (hasActiveConversationResult == null || !hasActiveConversationResult.Success)
                {
                    await channel.SendMessageAsync(AppConstants.UnableGetMember);
                    return;
                }
                bool hasActiveConversation = hasActiveConversationResult.Data;

                if (!(channel.CategoryId.Equals(guild.Preferences?.ChatsCategoryId) && hasActiveConversation))
                    return;

                if (!channel.Name.Contains(iuser.GlobalName.ToLower()))
                    return;

                EmbedBuilder embed = CreateInitialEmbed(guild);
                RestUserMessage botMessage = await channel.SendMessageAsync(embed: embed.Build());

                ApiResult<UserChatInfo>? infoResult = await _userService.GetChatInfoByChannel(user.Id, guild.Id, channel.Id);
                if (infoResult == null || !infoResult.Success || infoResult.Data == null)
                {
                    await ModifyMessageWithError(botMessage, embed, Program.LangManager.GetTranslation(guild, LanguageKeys.CouldNotFindInfo) + $" ({nameof(MessageReceivedHandler)})");
                    return;
                }
                UserChatInfo info = infoResult.Data;

                ApiResult<ChatModel>? modelResult = await _userService.GetLastModel(user.Id, guild.Id, channelId: channel.Id);
                if (modelResult == null || !modelResult.Success || modelResult.Data == null)
                {
                    await ModifyMessageWithError(botMessage, embed, Program.LangManager.GetTranslation(guild, LanguageKeys.CouldNotFindLastModel));
                    return;
                }
                ChatModel model = modelResult.Data;

                string prompt = message.Content;

                if (string.IsNullOrWhiteSpace(prompt))
                {
                    await ModifyMessageWithError(
                            botMessage,
                            embed.WithColor(Color.DarkOrange).WithFooter(AppConstants.AppName),
                            "Atualmente o sistema de chat só está disponível por mensagem."
                         );
                    return;
                }

                SocketGuildUser guildUser = socketGuild.GetUser(iuser.Id);

                ApiResult<IEnumerable<UserChatHistoric>>? historicsResult = await _userService!.GetChatHistory(user.Id, guild.Id, channel.Id);
                List<UserChatHistoric>? historics = historicsResult != null && historicsResult.Success ? historicsResult.Data?.ToList() : null;

                switch (model.Type)
                {
                    case ModelType.Chat:
                        await ProcessChatModel(guild, user, model, channel.Id, prompt, botMessage, embed, historics);
                        break;

                    case ModelType.Image:
                        await ProcessImageModel(guild, user, model, info, channel.Id, prompt, botMessage, embed, historics);
                        break;

                    case ModelType.TTS:
                        await ProcessTTSModel(guild, user, model, channel.Id, prompt, botMessage, embed, historics);
                        break;

                    default:
                        await UpdateBotMessage
                            (
                                botMessage,
                                new EmbedBuilder()
                                    .WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.CouldNotFindModel))
                                    .WithColor(Color.Red)
                            );
                        break;
                }
            }
            catch (Exception e)
            {
                await AresLogger.LogAsync(nameof(MessageReceivedHandler), "Can't process the content receiver.", severity: Severity.Error, extra: e.Message);
            }
        });

        return Task.CompletedTask;
    }

    private EmbedBuilder CreateInitialEmbed(Guild guild)
    {
        return new EmbedBuilder()
            .WithTitle(Program.LangManager.GetTranslation(guild, LanguageKeys.AI))
            .WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.ToProcess))
            .WithColor(Color.Gold)
            .WithFooter(Program.LangManager.GetTranslation(guild, LanguageKeys.TakeUpMinutes));
    }

    private async Task ModifyMessageWithError(RestUserMessage botMessage, EmbedBuilder embed, string errorMessage)
    {
        await botMessage.ModifyAsync(message =>
            message.Embeds = new[] { embed.WithDescription(errorMessage).Build() });
    }

    private async Task ProcessChatModel(
        Guild guild,
        User user,
        ChatModel model,
        ulong channelId,
        string prompt,
        RestUserMessage botMessage,
        EmbedBuilder embed,
        List<UserChatHistoric>? historics)
    {
        DateTime date = DateTime.Now;

        EmbedBuilder? priceEmbed = null;

        string menuId = $"chat-snippet-{StringUtil.GenerateExclusiveCode()}";

        SelectMenuBuilder menu = new SelectMenuBuilder()
            .WithPlaceholder("Lista de Trechos")
            .WithCustomId(menuId);

        var (result, success) = await NeuralService.GenerateConversationAsync(guild, user, model, channelId, prompt);

        if (success)
        {
            MatchCollection matches = Regex.Matches(result, "```(?:[a-zA-Z0-9]*\\n)?(.*?)```", RegexOptions.Singleline);

            uint index = 0;

            List<UserChatSnippet> snippets = new();

            foreach (Match match in matches)
            {
                string code = match.Groups[1].Value.Trim();
                if (string.IsNullOrWhiteSpace(code)) continue;

                UserChatSnippet snippet = new UserChatSnippet(channelId, botMessage.Id, index, code);

                snippets.Add(snippet);

                menu.AddOption(new SelectMenuOptionBuilder
                {
                    Label = $"Trecho n.º {snippet.getFormattedIndex()}",
                    Value = snippet.Id,
                });

                index++;
            }

            await _userService!.SaveSnippetsBatch(user.Id, guild.Id, snippets);

            // Set color based on model category
            Color color = AresUtil.GetColorByModelCategory(model.Category);

            const int Limit = 4096;

            // Handle Discord's description character limit
            if (result.Length > Limit)
            {
                embed.WithDescription(result.Substring(0, Limit))
                    .WithColor(color)
                    .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName} (♾️)");
            }
            else
            {
                embed.WithDescription(result)
                    .WithColor(color)
                    .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName}");
            }

            ApiResult<IEnumerable<UserChatHistoric>>? historicsResult = await _userService.GetChatHistory(user.Id, guild.Id, channelId: channelId);

            if (historicsResult == null || !historicsResult.Success)
            {
                embed.WithDescription(result)
                    .WithColor(Color.Red)
                    .WithFooter("Não foi possível acessar as informações do servidor atual");
            }
            else
            {
                // Atualiza o historico de chat após a geracão.
                historics = historicsResult.Data?.ToList();

                // Process pricing information
                priceEmbed = CreatePriceEmbedForChat(guild, model, historics);
            }
        }
        else
        {
            embed.WithDescription(result)
                .WithColor(Color.Red)
                .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName}");
        }

        await UpdateBotMessage(botMessage, embed, priceEmbed: priceEmbed, selectMenu: menu);
    }

    private async Task ProcessImageModel(
        Guild guild,
        User user,
        ChatModel model,
        UserChatInfo info,
        ulong channelId,
        string prompt,
        RestUserMessage botMessage,
        EmbedBuilder embed,
        List<UserChatHistoric>? historics)
    {
        ImageGenOptions options = info.ImageGenOptions ?? new ImageGenOptions();

        var (responseImageUrl, success) = await NeuralService.GenerateImageUrlAsync(guild, user, model, options, channelId, prompt);

        if (success)
        {
            // Check if the result is a valid URL
            if (WebUtil.IsValidUrl(responseImageUrl))
            {
                embed.WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.Success))
                    .WithColor(Color.Green)
                    .WithImageUrl(responseImageUrl);
            }
            else
            {
                embed.WithDescription(responseImageUrl)
                    .WithColor(Color.Red);
            }
        }
        else
        {
            embed.WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.UnableGenerateOrder))
                .WithColor(Color.Red);
        }

        // Process pricing information
        EmbedBuilder? priceEmbed = CreatePriceEmbedForImage(guild, model, historics, options);
        await UpdateBotMessage(botMessage, embed, priceEmbed);
    }

    private async Task ProcessTTSModel(
        Guild guild,
        User user,
        ChatModel model,
        ulong channelId,
        string prompt,
        RestUserMessage botMessage,
        EmbedBuilder embed,
        List<UserChatHistoric>? historics)
    {
        (string responseBinary, bool isAudio) = await NeuralService.GenerateTTSAsync(guild, user, model, channelId, prompt);

        // Set color based on model category
        Color color = AresUtil.GetColorByModelCategory(model.Category);
        DateTime date = DateTime.Now;

        Optional<IEnumerable<FileAttachment>>? attachments = null;

        // Handle Discord's description character limit
        if (string.IsNullOrEmpty(responseBinary) || !isAudio)
        {
            embed.WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.UnableGenerateOrder))
                .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName}");
        }
        else
        {
            try
            {
                BinaryData binaryData = BinaryData.FromString(responseBinary);
                MemoryStream memory = new MemoryStream();

                using (Stream stream = binaryData.ToStream())
                {
                    await stream.CopyToAsync(memory);
                }

                // Reposition MemoryStream to the beginning
                memory.Position = 0;

                embed.WithDescription($" TTS: {prompt}")
                    .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName}");

                long fileSize = memory.Length;

                AresLogger.Log("Audio", $"Audio file size: {fileSize} bytes");

                // If the file is very small (< 1KB), it is probably empty or corrupt.
                if (fileSize < 1024)
                {
                    embed.WithFooter("O arquivo de áudio é suspeitamente pequeno");
                }

                attachments = new Optional<IEnumerable<FileAttachment>>(
                    [
                    new FileAttachment(memory, "audio.mp3")
                    ]
                );
            }
            catch (Exception ex)
            {
                embed.WithDescription(Program.LangManager.GetTranslation(guild, LanguageKeys.UnableGenerateOrder))
                    .WithFooter($"{date.Year} - {AppConstants.AppName} | {model.DisplayName}");

                AresLogger.Log("TTS", "Unable to generate TTS audio.", severity: Severity.Error, extra: ex.Message);
            }
        }

        // Process pricing information
        // EmbedBuilder? priceEmbed = CreatePriceEmbedForChat(guild, model, historics);
        await UpdateBotMessage(botMessage, embed, /*priceEmbed,*/ attachments: attachments);
    }

    private EmbedBuilder? CreatePriceEmbedForChat(Guild guild, ChatModel model, List<UserChatHistoric>? historics)
    {
        if (historics == null || !historics.Any())
            return null;

        UserChatHistoric? historic = historics.LastOrDefault();
        if (historic == null)
            return null;

        ChatTokenUsage? usage = historic.Usage;
        ChatPriceUsage? price = model.Price;

        if (usage == null || price == null)
            return null;

        decimal inputPrice = usage.InputTokens * price.InputPriceTokenPerToken();
        decimal outputPrice = usage.OutputTokens * price.OutputPriceTokenPerToken();

        EmbedBuilder priceEmbed = new EmbedBuilder()
            // Input Field
            .AddField("Tokens", usage.InputTokens, true)
            .AddField(Program.LangManager.GetTranslation(guild, LanguageKeys.Request), $"$ {FormatterUtil.FormatPrice(inputPrice)}", true)
            // Broke Line
            .AddField("\u200B", "\u200B", false)
            // Output Field
            .AddField("Tokens", usage.OutputTokens, true)
            .AddField(Program.LangManager.GetTranslation(guild, LanguageKeys.Response), $"$ {FormatterUtil.FormatPrice(outputPrice)}", true)
            // Broke Line
            .AddField("\u200B", "\u200B", false)
            // Total Field
            .AddField("Tokens", usage.TotalTokens, true)
            .AddField(Program.LangManager.GetTranslation(guild, LanguageKeys.Total), $"$ {FormatterUtil.FormatPrice(inputPrice + outputPrice)}", true)
            .WithFooter(Program.LangManager.GetTranslation(guild, LanguageKeys.PriceLowerCache));

        return priceEmbed;
    }

    private EmbedBuilder? CreatePriceEmbedForImage(Guild guild, ChatModel model, List<UserChatHistoric>? historics, ImageGenOptions options)
    {
        if (historics == null || !historics.Any())
            return null;

        UserChatHistoric? historic = historics.LastOrDefault();
        if (historic == null)
            return null;

        ChatPriceUsage? price = model.Price;
        if (price == null)
            return null;

        List<ChatPriceUsageDetail>? priceDetails = price.ChatPriceUsageDetail;
        if (priceDetails == null)
            return null;

        ChatPriceUsageDetail? priceDetail = priceDetails.Find(x => x.Quality == options.Quality && x.Size == options.Size);
        if (priceDetail == null)
            return null;

        EmbedBuilder priceEmbed = new EmbedBuilder()
            .AddField(Program.LangManager.GetTranslation(guild, LanguageKeys.Total), $"$ {FormatterUtil.FormatPrice(priceDetail.Price)}", true)
            .WithFooter(AppConstants.AppName);

        return priceEmbed;
    }

    private async Task UpdateBotMessage(
        RestUserMessage botMessage,
        EmbedBuilder mainEmbed,
        EmbedBuilder? priceEmbed = null,
        SelectMenuBuilder? selectMenu = null,
        Optional<IEnumerable<FileAttachment>>? attachments = null)
    {
        // Fix in case someone deletes the channel before sending the message.
        if (botMessage == null) return;

        List<Embed> embeds = new List<Embed>();

        if (priceEmbed != null)
        {
            embeds.Add(priceEmbed.Build());
        }

        // Alert: Add the main embed at the end so it is the last one displayed
        embeds.Add(mainEmbed.Build());

        ComponentBuilder componentBuilder = new ComponentBuilder();

        if (selectMenu != null && selectMenu.Options.Count > 0)
        {
            componentBuilder.WithSelectMenu(selectMenu);
        }

        MessageComponent component = componentBuilder.Build();

        if (attachments != null)
        {
            var attachment = attachments.Value;
            await botMessage.ModifyAsync(message =>
            {
                message.Embeds = embeds.ToArray();
                message.Attachments = attachment;
                message.Components = component;
            });
        }
        else
        {
            await botMessage.ModifyAsync(message =>
            {
                message.Embeds = embeds.ToArray();
                message.Components = component;
            });
        }
    }
}

